		for (int i = 0; i < nonZeroVars.size(); i++) {
			if (!visited.add(i)) {
				continue;
			}
			components++;
			ArrayDeque<Integer> queue = new ArrayDeque<>();
			queue.add(i);
			visitConnectedComponent(nonZeroVars, visited, queue);
		}
		return components;
